#include <bits/stdc++.h>
using namespace std;
const int N=500005;
int n,m,a[N];
int fun(int x)
{
	int sum=0;
	for(int i=x;i>0;i-=(i&(-i))) sum+=a[i];
	return sum;
}
void add(int x,int k)
{
	for(int i=x;i<=n;i+=(i&(-i))) a[i]+=k;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		int k;
		cin>>k;
		add(i,k);
	}
	while(m--) 
	{
		int op,x,y;
		cin>>op>>x>>y;
		if(op==1) add(x,y);
		else cout<<fun(y)-fun(x-1)<<'\n';
	}
	return 0;
}
